import React from 'react'
import { ModalBackround, ModalContainer } from '../style/style.Components'
import { IoCloseSharp } from "react-icons/io5";

const Modal = (props) => {
  return (
    <ModalBackround>
      <IoCloseSharp/>
      <ModalContainer>
          {props.children}
      </ModalContainer>
    </ModalBackround>

  )
}

export default Modal
